// Helper to look up by municipality name (slug)
export function getMunicipalityInfo(name) {
  if (!name) return null
  const slug = name.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
    .replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,'')
  return MUNICIPALITY_INFO[slug] || null
}

